import{G as e,c as t,b as o,ae as r}from"./chunks/framework.Cpb2nuHT.js";const l="/assets/1761227277808.6v7aN3_D.png",i="/assets/1761228224823.CldC635E.png",p="/assets/1761228075116.d4W11ucO.png",u=JSON.parse('{"title":"JVM 初识","description":"","frontmatter":{"title":"JVM 初识","date":"2025/10/22 20:51","tags":["Java","JVM"],"author":"花木凋零成兰","hiddenCover":true},"headers":[],"relativePath":"Java/JVM/01_JVM初识.md","filePath":"Java/JVM/01_JVM初识.md","lastUpdated":1775139533000}'),s={name:"Java/JVM/01_JVM初识.md"};function n(J,a,c,d,h,V){return o(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1761166260000"},[...a[0]||(a[0]=[r('<h1 id="jvm-初识" tabindex="-1">JVM 初识 <a class="header-anchor" href="#jvm-初识" aria-label="Permalink to &quot;JVM 初识&quot;">​</a></h1><h2 id="什么是-jvm" tabindex="-1">什么是 JVM <a class="header-anchor" href="#什么是-jvm" aria-label="Permalink to &quot;什么是 JVM&quot;">​</a></h2><p>Java 虚拟机(JVM)全称 <em>Java Virtual Machine</em>, 本质上是一个在计算机上运行的程序, 专门用来运行 Java字节码文件;</p><p><img src="'+l+'" alt="JVM 虚拟机" loading="lazy"></p><h2 id="jvm-功能" tabindex="-1">JVM 功能 <a class="header-anchor" href="#jvm-功能" aria-label="Permalink to &quot;JVM 功能&quot;">​</a></h2><h3 id="解释和运行" tabindex="-1">解释和运行 <a class="header-anchor" href="#解释和运行" aria-label="Permalink to &quot;解释和运行&quot;">​</a></h3><p>将字节码文件解释为机器码, 让计算机执行;</p><h3 id="内存管理" tabindex="-1">内存管理 <a class="header-anchor" href="#内存管理" aria-label="Permalink to &quot;内存管理&quot;">​</a></h3><p>1、为 Java 对象,方法分配内存;</p><p>2、垃圾回收机制,自动回收不再使用的对象,提高内存利用率;</p><h3 id="即时编译-jit" tabindex="-1">即时编译(JIT) <a class="header-anchor" href="#即时编译-jit" aria-label="Permalink to &quot;即时编译(JIT)&quot;">​</a></h3><blockquote><p>即使编译(JIT): Just-in-time</p></blockquote><p>虽然 Java 需要在 JVM 上实时解释运行, 性能不如直接运行机器码的 C、C++;</p><p>但是 JVM 会对<strong>热点代码</strong>进行编译优化(通过将编译后的机器码保存在内存中, 下次再运行时不需要重复解释为机器码, 直接从内存中快速运行即可), 提高代码执行效率;</p><p><img src="'+i+'" alt="即使编译" loading="lazy"></p><p>同时因为有JVM 对字节码文件实时解释运行, 所以 Java 只需要对代码进行一次编译, 就可以在不同平台基于 JVM 直接运行, 即保证了跨平台性;</p><h2 id="常见-jvm" tabindex="-1">常见 JVM <a class="header-anchor" href="#常见-jvm" aria-label="Permalink to &quot;常见 JVM&quot;">​</a></h2><p><img src="'+p+'" alt="常见 JVM" loading="lazy"></p><h2 id="jvm-规范" tabindex="-1">JVM 规范 <a class="header-anchor" href="#jvm-规范" aria-label="Permalink to &quot;JVM 规范&quot;">​</a></h2><blockquote><p><a href="https://docs.oracle.com/javase/specs/index.html" target="_blank" rel="noreferrer">JVM 规范官网</a></p></blockquote><p>JVM 规范由 Oracle 制定, 主要包含 JVM 在设计和实现时需要遵守的规范: class 字节码文件的定义、类和接口的加载和初始化、指令集等内容;</p><p>JVM 规范是对虚拟机设计的要求, 不是对 Java 设计的要求, 即虚拟机也可以运行其他语言生成的 class 字节码文件;</p><h2 id="问题自测" tabindex="-1">问题自测 <a class="header-anchor" href="#问题自测" aria-label="Permalink to &quot;问题自测&quot;">​</a></h2><p>1、JVM 到底是什么?</p><blockquote><p>JVM 即 Java 虚拟机, 全称 Java Virtual Machine, 是在计算机上运行的程序, 负责运行 Java 字节码文件;</p></blockquote><p>2、JVM 的三大核心功能是什么?</p><blockquote><p>1、解释和运行: 解释 Java 字节码文件, 并运行</p><p>2、内存管理: 为 Java 对象、方法分配内存, 并自动回收不再使用的对象;</p><p>3、即使编译: JIT, 优化热点代码的编译运行, 提高 Java 执行效率</p></blockquote><p>3、常见的 JVM 虚拟机有哪些?</p><blockquote><p>HotSpot、DragonWell龙井、GraalVM</p></blockquote>',29)])])}const M=e(s,[["render",n]]);export{u as __pageData,M as default};
